// Define a function to calculate the total height of the grid
function calculateGridHeight(gridItems) {
  let totalHeight = 0;
  let maxHeight = 0;
  let rows = 3;
  for (let item in gridItems) {
    totalHeight += parseInt(gridItems[item]);
    maxHeight = Math.max(maxHeight, parseInt(gridItems[item]));
  }
  // Add gaps between rows
  let gapHeight = (rows - 1) * maxHeight;
  return totalHeight + gapHeight;
}

