class Solution:
  def calculateGridHeight(self, gridItems: dict) -> int:
    totalHeight = 0;
    maxHeight = 0;
    rows = 3;
    for item in gridItems:
      totalHeight += int(gridItems[item]);
      maxHeight = max(maxHeight, int(gridItems[item]));
    # Add gaps between rows
    gapHeight = (rows - 1) * maxHeight;
    return totalHeight + gapHeight;
